+import SwiftUI
+#if canImport(UIKit)
+import UIKit
+#endif
+
+// MARK: - Parsed table model
+
+/// A GFM pipe-table parsed out of assistant markdown so it can be rendered by
+/// `MarkdownTableView` instead of MarkdownUI's built-in table.
+///
+/// Why a custom renderer: MarkdownUI's table locks each row's height to its
+/// single-line measurement before constraining column widths, so capping a
+/// column width makes long cells either truncate or overflow into the next row.
+/// Rendering with a plain `HStack`/`VStack` lets each row grow to its tallest
+/// wrapped cell, which is what gives "size to content up to a max, then wrap".
+struct MarkdownTable: Equatable {
+    enum CellAlignment: Equatable { case leading, center, trailing }
+
+    let headers: [String]
+    let alignments: [CellAlignment]
+    /// Body rows, each normalized to `headers.count` cells.
+    let rows: [[String]]
+
+    // MARK: Parsing helpers
+
+    /// True if `line` is a GFM delimiter row, e.g. `|---|:--:|---:|`.
+    static func isDelimiterRow(_ line: String) -> Bool {
+        let cells = splitCells(line)
+        guard !cells.isEmpty else { return false }
+        let pattern = "^:?-+:?$"
+        return cells.allSatisfy { cell in
+            let c = cell.trimmingCharacters(in: .whitespaces)
+            guard !c.isEmpty else { return false }
+            return c.range(of: pattern, options: .regularExpression) != nil
+        }
+    }
+
+    /// Split a table row into trimmed cells, honoring escaped pipes (`\|`) and
+    /// optional leading/trailing outer pipes.
+    static func splitCells(_ line: String) -> [String] {
+        let placeholder = "\u{0}"
+        var t = line.replacingOccurrences(of: "\\|", with: placeholder)
+            .trimmingCharacters(in: .whitespaces)
+        if t.hasPrefix("|") { t.removeFirst() }
+        if t.hasSuffix("|") { t.removeLast() }
+        return t.components(separatedBy: "|").map {
+            $0.replacingOccurrences(of: placeholder, with: "|")
+                .trimmingCharacters(in: .whitespaces)
+        }
+    }
+
+    private static func alignment(for delimiterCell: String) -> CellAlignment {
+        let c = delimiterCell.trimmingCharacters(in: .whitespaces)
+        let left = c.hasPrefix(":")
+        let right = c.hasSuffix(":")
+        switch (left, right) {
+        case (true, true): return .center
+        case (false, true): return .trailing
+        default: return .leading
+        }
+    }
+
+    /// Build a table from its header line, delimiter line, and body lines.
+    static func make(headerLine: String, delimiterLine: String, bodyLines: [String]) -> MarkdownTable {
+        let headers = splitCells(headerLine)
+        let count = headers.count
+        let delims = splitCells(delimiterLine)
+        var alignments = delims.map { alignment(for: $0) }
+        // Normalize alignment count to the header column count.
+        if alignments.count < count {
+            alignments.append(contentsOf: Array(repeating: .leading, count: count - alignments.count))
+        } else if alignments.count > count {
+            alignments = Array(alignments.prefix(count))
+        }
+        let rows = bodyLines.map { line -> [String] in
+            var cells = splitCells(line)
+            if cells.count < count {
+                cells.append(contentsOf: Array(repeating: "", count: count - cells.count))
+            } else if cells.count > count {
+                cells = Array(cells.prefix(count))
+            }
+            return cells
+        }
+        return MarkdownTable(headers: headers, alignments: alignments, rows: rows)
+    }
+}
+
+// MARK: - Text width measurement
+
+enum TableTextMeasurer {
+    /// Single-line rendered width of `text` in the chat table font, with font
+    /// substitution for CJK glyphs. Used to size each column to its content.
+    static func width(_ text: String, semibold: Bool) -> CGFloat {
+        let size = AppTheme.Chat.tableCellSize
+        #if canImport(UIKit)
+        let weight: UIFont.Weight = semibold ? .semibold : .medium
+        let base = UIFont(name: AppTheme.Chat.fontFamily, size: size)
+            ?? UIFont.systemFont(ofSize: size, weight: weight)
+        // Nudge the variable font toward the rendered weight so measurement
+        // doesn't under-size semibold headers and clip them.
+        let descriptor = base.fontDescriptor.addingAttributes(
+            [.traits: [UIFontDescriptor.TraitKey.weight: weight]]
+        )
+        let font = UIFont(descriptor: descriptor, size: size)
+        let attributed = NSAttributedString(string: text, attributes: [.font: font])
+        let rect = attributed.boundingRect(
+            with: CGSize(width: CGFloat.greatestFiniteMagnitude, height: CGFloat.greatestFiniteMagnitude),
+            options: [.usesLineFragmentOrigin],
+            context: nil
+        )
+        return ceil(rect.width) + 2 // small safety pad against sub-pixel clipping
+        #else
+        // macOS fallback estimate (chat is iOS-first): CJK ≈ 1em, others ≈ 0.55em.
+        let estimate = text.unicodeScalars.reduce(CGFloat(0)) { acc, scalar in
+            acc + (scalar.value > 0x2E80 ? size : size * 0.55)
+        }
+        return ceil(estimate) + 2
+        #endif
+    }
+}
+
+// MARK: - Table view
+
+/// Renders a `MarkdownTable` as a horizontally scrollable, horizontal-rules-only
+/// table matching the `.pandaAssistant` editorial style: Lora serif, semibold
+/// header row + first column, columns sized to content up to a max width then
+/// wrapping onto multiple lines.
+struct MarkdownTableView: View {
+    let table: MarkdownTable
+
+    private let cellPadding: CGFloat = 8
+
+    private var columnWidths: [CGFloat] {
+        let count = table.headers.count
+        guard count > 0 else { return [] }
+        let pad = cellPadding * 2
+        let minW = AppTheme.Chat.tableCellMinWidth
+        let maxW = AppTheme.Chat.tableCellMaxWidth
+        return (0..<count).map { col in
+            var natural = TableTextMeasurer.width(table.headers[col], semibold: true)
+            for row in table.rows where col < row.count {
+                natural = max(natural, TableTextMeasurer.width(row[col], semibold: col == 0))
+            }
+            return min(max(natural + pad, minW), maxW)
+        }
+    }
+
+    var body: some View {
+        let widths = columnWidths
+        let totalWidth = widths.reduce(0, +)
+        ScrollView(.horizontal, showsIndicators: false) {
+            VStack(alignment: .leading, spacing: 0) {
+                rule(width: totalWidth)
+                rowView(table.headers, widths: widths, isHeader: true)
+                rule(width: totalWidth)
+                ForEach(Array(table.rows.enumerated()), id: \.offset) { _, row in
+                    rowView(row, widths: widths, isHeader: false)
+                    rule(width: totalWidth)
+                }
+            }
+        }
+    }
+
+    @ViewBuilder
+    private func rule(width: CGFloat) -> some View {
+        Rectangle()
+            .fill(AppTheme.Chat.dividerColor)
+            .frame(width: width, height: 1)
+    }
+
+    @ViewBuilder
+    private func rowView(_ cells: [String], widths: [CGFloat], isHeader: Bool) -> some View {
+        HStack(alignment: .top, spacing: 0) {
+            ForEach(0..<widths.count, id: \.self) { col in
+                let text = col < cells.count ? cells[col] : ""
+                cellView(
+                    text,
+                    width: widths[col],
+                    semibold: isHeader || col == 0,
+                    alignment: col < table.alignments.count ? table.alignments[col] : .leading
+                )
+            }
+        }
+    }
+
+    @ViewBuilder
+    private func cellView(_ text: String, width: CGFloat, semibold: Bool, alignment: MarkdownTable.CellAlignment) -> some View {
+        Text(inlineAttributed(text))
+            .font(.custom(AppTheme.Chat.fontFamily, size: AppTheme.Chat.tableCellSize))
+            .fontWeight(semibold ? .semibold : .medium)
+            .foregroundStyle(AppTheme.Chat.textColor)
+            .lineSpacing(AppTheme.Chat.tableCellLineSpacingEm * AppTheme.Chat.tableCellSize)
+            .multilineTextAlignment(textAlignment(alignment))
+            .padding(cellPadding)
+            .frame(width: width, alignment: frameAlignment(alignment))
+            .fixedSize(horizontal: false, vertical: true)
+    }
+
+    /// Parse inline markdown (bold/italic/code) in a cell; fall back to plain.
+    private func inlineAttributed(_ raw: String) -> AttributedString {
+        let options = AttributedString.MarkdownParsingOptions(
+            interpretedSyntax: .inlineOnlyPreservingWhitespace
+        )
+        if let attributed = try? AttributedString(markdown: raw, options: options) {
+            return attributed
+        }
+        return AttributedString(raw)
+    }
+
+    private func textAlignment(_ alignment: MarkdownTable.CellAlignment) -> TextAlignment {
+        switch alignment {
+        case .leading: return .leading
+        case .center: return .center
+        case .trailing: return .trailing
+        }
+    }
+
+    private func frameAlignment(_ alignment: MarkdownTable.CellAlignment) -> Alignment {
+        switch alignment {
+        case .leading: return .leading
+        case .center: return .center
+        case .trailing: return .trailing
+        }
+    }
+}

