+'use client'
+
+import type { ReactNode } from 'react'
+
+import type { useChatReplayShare } from '../../hooks/useChatReplayShare'
+import ChatShareCreatedDialog from './ChatShareCreatedDialog'
+import ChatShareSelectionBar from './ChatShareSelectionBar'
+import { ShareSelectionProvider } from './ChatShareSelectionContext'
+
+type ShareFlow = ReturnType<typeof useChatReplayShare>
+
+export function ChatShareFlowFrame({ shareFlow, children }: { shareFlow: ShareFlow; children: ReactNode }) {
+  return (
+    <ShareSelectionProvider
+      value={{
+        enabled: shareFlow.state.enabled,
+        selectedIds: shareFlow.state.selectedIds,
+        selectableIds: shareFlow.state.selectableIds,
+        toggle: shareFlow.actions.toggle,
+      }}
+    >
+      {children}
+      {shareFlow.state.enabled ? (
+        <ChatShareSelectionBar
+          selectedCount={shareFlow.state.selectedIds.size}
+          selectableCount={shareFlow.state.selectableCount}
+          creating={shareFlow.state.creating}
+          onCancel={shareFlow.actions.exit}
+          onSelectVisible={shareFlow.actions.selectVisible}
+          onClear={shareFlow.actions.clear}
+          onCreate={() => void shareFlow.actions.create()}
+        />
+      ) : null}
+      {shareFlow.state.createdShare && (
+        <ChatShareCreatedDialog
+          share={shareFlow.state.createdShare}
+          onDismiss={shareFlow.actions.dismissCreatedDialog}
+          onRevoke={shareFlow.actions.revokeCreated}
+        />
+      )}
+    </ShareSelectionProvider>
+  )
+}

